@Service
@RequiredArgsConstructor
public class ProfileService {

 private final UserRepository userRepository;

 @PreAuthorize("isAuthenticated()")
 public ProfileDto getProfile(String username, String curUsername){
 //Находим пользователя в базы
 User user = userRepository.findByUsername(username).orElseThrow(()->
 new UsernameNotFoundException("Profile with username: " + username + " not found"));

 //Проверяем юзернейм владельца профиля и пользователя
 boolean isOwner = user.getUsername().equals(curUsername);

 //В зависимости от того, владелец или нет, возвращаем Dto с разным наполнением
 return isOwner ? ProfileDto.ownerView(user) : ProfileDto.publicView(user);
 }

 @Transactional
 @PreAuthorize("hasRole('ADMIN') or #username == authentication.name")
 public ProfileDto updateProfile(String username, UpdateProfileRequest request){
 User user = userRepository.findByUsername(username).orElseThrow(() ->
 new UsernameNotFoundException("Profile with username: " + username + " not fund"));

 user.setDisplayName(request.displayName());
 user.setAvatarUrl(request.avatarUrl());
 user.setStatus(request.status());
 user.setPhoneNumber(request.phoneNumber());
 user.setEmail(request.email());

 //Можем спокойно не писать userRepository.save(user); Поскольку user уже в persistence контексте и hibernate следит за его изменениями
 return ProfileDto.ownerView(user);
 }

 @Transactional
 @PreAuthorize("hasRole('ADMIN') or #username == authentication.name")
 public void delete(String username){
 User user = userRepository.findByUsername(username).orElseThrow(() ->
 new UsernameNotFoundException("Profile with username: " + username + " not fund"));
 user.setEnabled(false);
 }
}
